void func_a(){
    int i = 0;
    size_t rows = sizeof(items) / sizeof(items[0]);
    size_t cols = sizeof(items[0]);

    for (;;) {
        if ((size_t)i >= rows) {
            break; // prevent writing past the end of items
        }

        printf("input item:");
        char* buff = &items[i][0];

        if (fgets(buff, (int)cols, stdin) == NULL) {
            break; // EOF or read error
        }

        buff[strcspn(buff, "\n")] = '\0';

        if (strlen(buff) == 0) {
            break; // empty line ends input
        }

        i++;
    }

    i--;
}
